import{_ as p,o as d,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"沃伦·巴菲特合伙有限公司 1967-1969年致合伙人信（全文翻译）","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1967年/翻译.md","filePath":"01_letters/1967年/翻译.md"}'),e={name:"01_letters/1967年/翻译.md"};function o(l,t,h,i,n,s){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="沃伦·巴菲特合伙有限公司-1967-1969年致合伙人信-全文翻译" tabindex="-1"><a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙有限公司 1967-1969年致合伙人信（全文翻译） <a class="header-anchor" href="#沃伦·巴菲特合伙有限公司-1967-1969年致合伙人信-全文翻译" aria-label="Permalink to &quot;[[沃伦·巴菲特]]合伙有限公司 1967-1969年致合伙人信（全文翻译）&quot;">​</a></h1><h2 id="_1967年上半年信" tabindex="-1">1967年上半年信 <a class="header-anchor" href="#_1967年上半年信" aria-label="Permalink to &quot;1967年上半年信&quot;">​</a></h2><p>年初我们持有未实现收益16,361,974美元。截至6月30日，我们已实现净资本利得7,084,104美元，因此今年很可能会将年初归属你们的未实现收益中相当大一部分变现。这一数额已在1967年2月2日信件的第三项中告知各位。该信件副本及税务说明函将于11月寄给你们，届时会大致说明税务情况。</p><p>正如我一贯建议的，中期预估税款最稳妥的方式是按1966年实际税额缴纳1967年预估税，这样不会产生任何罚金。</p><p>无论最终收益数额如何，目前来看绝大部分将是长期资本利得，短期利得与普通收益（若有）占比极小。（我认为“收益-本金”的错误观念值得我用温和的言辞好好批判一番。就像我刚结婚时对苏西说的：“别纠结收益，只看最终结果。”）</p><h3 id="其他事项" tabindex="-1">其他事项 <a class="header-anchor" href="#其他事项" aria-label="Permalink to &quot;其他事项&quot;">​</a></h3><p>上半年，斯坦·佩里梅特因全职投身投资管理工作，辞去清算委员会职务。资深合伙人、经验丰富的投资者小弗雷德·斯坦巴克经其余成员选举，填补了该空缺。</p><p>与往年一样，我们将于11月11日左右发布年度报告、承诺函，并附上1967年税务情况粗略预估。</p><p>此外，10月我们将发出一封特别信件（以提醒各位重点关注）。信件内容不涉及合伙协议变更，但会对几项“基本规则”进行逐步调整，希望各位在制定1968年计划前有充足时间斟酌。合伙协议是我们之间的法律约定，而“基本规则”是私人约定，在某些层面更为重要。我认为任何规则变更都必须在影响合伙业务或业绩前明确说明与解释——因此才有这封10月的信件。</p><p>此致</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><hr><h2 id="_1967年10月9日-致合伙人" tabindex="-1">1967年10月9日 致合伙人 <a class="header-anchor" href="#_1967年10月9日-致合伙人" aria-label="Permalink to &quot;1967年10月9日 致合伙人&quot;">​</a></h2><p>过去十一年，我始终将<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙公司（BPL）的投资目标设定为：年均业绩跑赢道琼斯工业平均指数10个百分点。在当时的市场环境下，我认为这一目标虽有难度，但可以实现。</p><p>当前以下情况使得调整业绩基准成为必要：</p><ol><li><p>过去十年市场环境持续变化，显而易见的量化投资标的数量大幅减少；</p></li><li><p>市场对投资业绩的关注度急剧攀升（颇具讽刺的是，数年前只有少数人像我一样强调业绩的重要性），催生了高度敏感的市场走势，我的分析方法对此效用有限；</p></li><li><p>公司资本金规模扩大至约6500万美元，而优质投资机会愈发稀缺，这一问题在1967年1月信件中已提及；</p></li><li><p>我个人的诉求，希望不再像年轻时那样为追求卓越业绩而过度紧绷。</p></li></ol><p>下面我详细说明这些因素：</p><p>投资证券与企业的评估，向来结合定性与定量因素。极端来看，纯定性分析师会说：“买对公司（前景、行业格局、管理层俱佳），价格自然会跟上。”而纯定量分析师则认为：“买对价格，公司与股票自然会有表现。”在证券市场中，两种方法都能赚钱，多数分析师会兼顾两者，归类仅取决于对不同因素的侧重。</p><p>有趣的是，尽管我自认主要属于定量派（此刻课间休息没人回来，我可能是教室里唯一留下的人），但这些年我最成功的投资，大多源于定性层面的“高确定性洞察”，这才是真正赚大钱的关键。不过这类洞察十分罕见，而定量投资无需灵感——数据会像棒球棒一样狠狠砸在你眼前。因此，<strong>大钱靠定性决策，稳钱靠定量决策</strong>。</p><p>这些年量化低价股几乎消失，原因可能是过去二十年市场被反复挖掘，且未出现30年代那样的经济动荡打压股市、催生大量低价股；也可能是收购要约日益普遍，天然聚焦低价标的；还可能是分析师数量暴增，对标的研究远超以往。无论原因如何，我们赖以生存的量化低价股几乎绝迹，偶尔才会出现一两个。当然，我仍有能力对少数标的做出重要定性判断，这是我们获取大额利润的最佳机会，但此类机会极少。过去三年我们的优异业绩，很大程度就来自一次这样的定性投资。</p><p>第二个问题是市场对业绩的狂热追捧。多年来我一直强调业绩衡量的重要性，反复告诉合伙人：若我们业绩不及平均水平，资金就该投向别处。近年这一理念在投资界席卷开来，近一两年更是如潮水般泛滥，我认为这是一个合理理念被扭曲了。</p><p>我一直提醒合伙人，判断业绩至少要看三年。但随着市场狂热，投资者的预期周期不断缩短，巨额资金开始按年、按季、按月甚至更短时间衡量业绩（即所谓“即时研究”）。短期优异业绩带来巨额回报，既包括实际收益，也能吸引新资金入场，形成自我循环，导致海量资金在越来越短的周期内频繁交易。随之而来的问题是，投资标的本身愈发不重要，有时几乎无关紧要。</p><p>在我看来，这正在催生愈演愈烈的投机行为。这并非新现象，但如今大量原本稳健的专业投资者也被迫跟风，让投机多了一层新维度。这场游戏被体面的仪式、人物和术语包装，至今获利丰厚，未来或许会成为市场常态。但我确信自己不擅长这种操作，正如我在上一年年报第五页所说：</p><p>“此外，我们不会追随市场主流，去投资那些以预判市场走势凌驾于企业估值之上的标的。这种所谓‘潮流投资’近年快速赚得巨额利润（我写这封信的1月仍是如此）。我无法证实或否认这种方法的合理性，它既不符合我的认知（或许是偏见），更与我的性格相悖。我不会用自己的钱这么做——当然，也绝不会用你们的钱。”</p><p>证券市场中巨额资金的过度交易，会给所有参与者带来风险。我从不试图预测股市走势，完全不知道一年后道指会是600点、900点还是1200点。即便当前投机行为未来会引发严重后果，经验也表明预判时间毫无意义。但我确信，当前环境会让我们中期内的投资难度加大。</p><p>这或许只是“老顽固心态”（毕竟我37岁了）。当游戏规则不再适合自己时，人总会觉得新方法全错、注定失败。我过去也鄙视过这种行为，也见过固守旧观念、无视现实的代价。本质上，我与当下市场格格不入。但有一点我很明确：<strong>我不会放弃自己理解逻辑的方法，即便它难以应用；也不会为了看似轻松的暴利，去拥抱自己不完全理解、从未成功实践、可能导致本金永久亏损的方法</strong>。</p><p>第三个问题是资本金规模过大。过去我的投资机会数量是资本金的1.1倍到10倍，从未想过会有改变。我承诺过机会不足时会告知合伙人，1967年1月的信件中我兑现了这一承诺。受前两个因素影响，更大的资本金如今对业绩形成一定拖累。我认为这是四个因素中影响最小的，即便资本金缩减至现在的十分之一，我们的业绩也不会好太多，但规模扩大确实是负面因素。</p><p>最后也是最重要的因素，是个人动机。创立合伙公司时，我把“跑赢道指10个点”的目标设为自己的动力。那时我更年轻、更清贫，也更有好胜心。即便没有前三个外部因素，个人状态的变化也让我觉得该降低目标强度。我见过太多人在生活尤其是商业中，固守早已失去意义的习惯，且随着年龄增长愈发顽固。伯特兰·罗素曾讲过一个故事：一战后，两个立陶宛女孩住在他的庄园里，每晚天黑后都会偷偷出去偷邻居的蔬菜藏在房间里——尽管罗素家食物充足。罗素告诉她们，这种行为在战时立陶宛合理，但在英国乡村毫无必要。女孩们点头称是，却依旧继续偷窃。</p><p>罗素最后感慨，她们的行为看似怪异，其实与老洛克菲勒并无二致。</p><p>简单的自我分析告诉我，只要公开承诺了目标，面对信任我的合伙人，我就会全力以赴。而这种全力以赴如今越来越没必要。我希望有一个能兼顾非经济活动的财务目标，这可能意味着投身投资之外的领域，或是在投资中选择不追求最高回报的方向。比如继续持有一家尚可（但不算顶尖）的控股企业，我喜欢管理层与业务模式，即便其他投资预期回报更高。低价收购再转卖企业能赚更多钱，但长期持有、通过财务策略小幅提升业绩，或许更令人愉悦（尤其是当额外资金的个人价值降低时）。</p><p>因此，我会专注于<strong>简单、稳妥、盈利、愉悦</strong>的事。这不会让我们的运营比过去更保守，我始终认为我们一直相当稳健。长期下行风险不会降低，只是上行潜力有所收窄。</p><p>具体而言，我们的长期新目标是：<strong>年均收益取9%，或跑赢道指5个百分点，以较低者为准</strong>。比如未来五年道指年均-2%，我们争取+3%；若道指年均+12%，我们争取+9%。这些目标看似保守，但我认为在当前环境下，实现这些温和目标的难度，不亚于过去实现跑赢道指10个点的目标。此外，我希望温和的目标能让我减少过度投入（反之亦然）。</p><p>我会将这一新目标纳入11月1日左右寄发的基本规则，同时附上1968年承诺函。我提前发出这封信，是希望各位有充足时间考量个人情况，如需沟通解惑，可在做出1968年决定前联系我。和以往一样，我几乎会把全部个人资金（数据文档公司股票除外）与家族资金继续投入BPL。我认为合理可实现的目标，或许与各位的预期不同。若合伙人有更好的投资选择，完全可以将资金投向别处，我完全理解。</p><p>我一直反感公开宣称一套目标与动机，实际却遵循另一套的行为。因此我始终对各位坦诚目标与个人想法，避免你们依据虚假承诺做出重要决策（我在投资中遇到过不少此类情况）。显然，信中提及的所有情况并非突然出现，其中一些我已思考许久。</p><p>各位肯定能理解，我希望在完成过往目标后，再下调未来目标。除非已兑现此前承诺，否则我不会降低“奋斗强度”。</p><p>若各位对信件内容有任何疑问，欢迎随时告知。</p><p>此致</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><hr><h2 id="_1968年1月24日-1967年业绩说明" tabindex="-1">1968年1月24日 1967年业绩说明 <a class="header-anchor" href="#_1968年1月24日-1967年业绩说明" aria-label="Permalink to &quot;1968年1月24日 1967年业绩说明&quot;">​</a></h2><p>按多数标准来看，1967年我们表现出色。合伙公司整体收益35.9%，道指收益19.0%，超额完成了跑赢道指10个点的原目标。总收益19,384,250美元，即便通胀加剧，也能买不少百事<a href="/03_companies/可口可乐.html">可口可乐</a>。由于卖出部分长期重仓证券，我们实现应税收入27,376,667美元，这与1967年业绩无关，但会让各位在4月15日报税时深刻感受到“伟大社会”的参与感。</p><p>但细看1967年股市实际情况，这些喜悦会打些折扣。去年股市参与者跑赢道指的比例，可能创下历史新高。我尚无最终统计，但猜测至少95%的股票型投资公司业绩优于道指，很多差距极大。这是一个<strong>收益与年龄成反比</strong>的年份，而我在投资理念上属于“老年组”。</p><p>下表列示道指、合伙公司（分配前）及有限合伙人年度业绩：</p><table tabindex="0"><thead><tr><th>年份</th><th>道指整体收益</th><th>合伙公司收益</th><th>有限合伙人收益</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>38.5%</td><td>40.9%</td><td>32.2%</td></tr><tr><td>1959</td><td>20.0%</td><td>25.9%</td><td>20.9%</td></tr><tr><td>1960</td><td>-6.2%</td><td>22.8%</td><td>18.6%</td></tr><tr><td>1961</td><td>22.4%</td><td>45.9%</td><td>35.9%</td></tr><tr><td>1962</td><td>-7.6%</td><td>13.9%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.6%</td><td>38.7%</td><td>30.5%</td></tr><tr><td>1964</td><td>18.7%</td><td>27.8%</td><td>22.3%</td></tr><tr><td>1965</td><td>14.2%</td><td>47.2%</td><td>36.9%</td></tr><tr><td>1966</td><td>-15.6%</td><td>20.4%</td><td>16.8%</td></tr><tr><td>1967</td><td>19.0%</td><td>35.9%</td><td>28.4%</td></tr><tr><td><strong>累计与复合收益</strong>：</td><td></td><td></td><td></td></tr></tbody></table><p>1957-1967年，道指累计收益165.3%，年均复合9.3%；合伙公司累计1606.9%，年均复合29.4%；有限合伙人累计932.6%，年均复合23.6%。</p><h3 id="投资公司对比" tabindex="-1">投资公司对比 <a class="header-anchor" href="#投资公司对比" aria-label="Permalink to &quot;投资公司对比&quot;">​</a></h3><p>同期大型共同基金与封闭式基金业绩远逊于我们，有限合伙人23.6%的年均复合收益，大幅领先行业平均水平。</p><p>去年我曾说：“少数共同基金与私募投资机构业绩远超道指，部分甚至优于<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙公司，但它们的投资方法与我们截然不同，我并不擅长。”1967年这一情况加剧，众多机构收益远超BPL，部分涨幅超100%。巨额资金、人才与精力涌入，追求快速暴利，在我看来是愈发疯狂的投机，伴随巨大风险，但很多支持者却不以为然。</p><p>我的导师<a href="/04_people/本·格雷厄姆.html">本·格雷厄姆</a>曾说：“投机不违法、不缺德，但也不赚钱。”过去一年，靠投机就能轻松获利，我们依旧坚持稳健投资。若市场普遍出现问题，我们难免也会受影响。</p><h3 id="_1967年业绩分析" tabindex="-1">1967年业绩分析 <a class="header-anchor" href="#_1967年业绩分析" aria-label="Permalink to &quot;1967年业绩分析&quot;">​</a></h3><p>整体数据掩盖了不同投资组合的巨大差异：</p><ol><li><p><strong>套利类（Workout）</strong>：创历史最差表现，年均投资17,246,879美元，仅收益153,273美元，回报率0.89%，远低于往年10%以上的水平。我们集中投资少数套利标的，长期看能保证收益，但1967年表现极差。</p></li><li><p><strong>控股企业</strong>：拖累相对业绩，年均投资20,192,776美元，收益2,894,571美元。牛市中这类资产表现偏弱是正常的，1967年我们通过多元零售公司与<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>·<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>，收购了联合棉花商店、国民赔偿保险公司及关联公司，管理层表现卓越，远超预期。控股企业的稳定收益，也是我下调投资目标的原因之一——与靠谱的人做喜欢的生意，获得10%-12%的合理回报，没必要为了几个百分点的收益频繁交易。我们会将不超过40%的资金配置于控股企业，兼顾流动性。</p></li><li><p><strong>低估普通股类</strong>：表现极佳，年均投资19,487,996美元，收益14,096,593美元，回报率72%。核心收益来自一只重仓股（占比达40%上限），1964-1967年持续爆发，1967年我们已大幅减持，目前暂无同等规模与潜力的标的。</p></li><li><p><strong>私人股权类</strong>：收益良好，年均投资5,141,710美元，收益1,297,215美元，当前仍有少量机会。</p></li></ol><h3 id="其他事项-1" tabindex="-1">其他事项 <a class="header-anchor" href="#其他事项-1" aria-label="Permalink to &quot;其他事项&quot;">​</a></h3><p>年初公司净资产68,108,088美元，约160万美元资金因10月信件的目标下调而退出，这对双方都是合理选择。有人问我是否在逐步解散合伙公司，答案是<strong>绝对不会</strong>。只要合伙人愿意与我共同出资，且业务运营愉快，我会一直与信任我的伙伴合作。</p><p>格拉迪斯·凯泽加入团队，表现出色。1968年1月1日，团队及家属在BPL的投资超1500万美元，无需靠咖啡因支撑工作。</p><p>近日各位将收到：</p><ol><li><p>1967年联邦报税所需税务说明函；</p></li><li><p>皮特·马威克会计师事务所出具的1967年审计报告；</p></li><li><p>我签署的1968年1月1日合伙权益确认函。</p></li></ol><p>下次信件将于7月15日左右发出，总结上半年业绩。</p><p>此致</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><hr>',61)])])}const m=p(e,[["render",o]]);export{c as __pageData,m as default};
